          if (agd && agd.targetHeight && !isNaN(agd.targetHeight)) {
            mphInfo = ` (Twój docelowy wzrost na podstawie wzrostu rodziców to ok. ${agd.targetHeight.toFixed(1).replace('.', ',')} cm ±8,5 cm, więc ta prognoza jest tylko orientacyjna)`;
          }
