      const isBMIOver    = (bmiCat === 'Nadwaga' || String(bmiCat).startsWith('Otyłość'));
      const isColeOver   = (coleCat === 'Nadwaga' || String(coleCat).startsWith('Otyłość'));
      const isBMIUnder   = (bmiCat === 'Niedowaga');
      const isColeUnder  = (coleCat === 'Niedowaga');

